fn dec_Library(alloc: std.mem.Allocator, src: Value, out: *types.Library) CodecError!void {
    _ = alloc;
    const csil_s = try as_text(src);
    if (std.mem.eql(u8, csil_s, "music")) {
        out.* = .music;
        return;
    }
