/// Encode a Role to CBOR. The returned slice is owned by the caller
/// (free it with alloc.free).
pub fn encode_Role(alloc: std.mem.Allocator, v: *const types.Role) CodecError![]u8 {
    var out = std.ArrayList(u8).init(alloc);
    errdefer out.deinit();
    try enc_Role(&out, v);
    return out.toOwnedSlice();
}

/// Decode CBOR into a Role. Every string/slice/map inside `out` is
/// allocated from `alloc`; pass an arena and free it all at once.
pub fn decode_Role(alloc: std.mem.Allocator, bytes: []const u8, out: *types.Role) CodecError!void {
    const root = try decode(alloc, bytes);
    try dec_Role(alloc, root, out);
}

/// Encode a PlayerStatus to CBOR. The returned slice is owned by the caller
/// (free it with alloc.free).
pub fn encode_PlayerStatus(alloc: std.mem.Allocator, v: *const types.PlayerStatus) CodecError![]u8 {
    var out = std.ArrayList(u8).init(alloc);
    errdefer out.deinit();
    try enc_PlayerStatus(&out, v);
    return out.toOwnedSlice();
}

/// Decode CBOR into a PlayerStatus. Every string/slice/map inside `out` is
/// allocated from `alloc`; pass an arena and free it all at once.
pub fn decode_PlayerStatus(alloc: std.mem.Allocator, bytes: []const u8, out: *types.PlayerStatus) CodecError!void {
    const root = try decode(alloc, bytes);
